test_that("ci_tree_validation_gain scores a fitted partition", {
  toy_data <- data.frame(
    rank = c(10, 20, 30, 40, 50, 60),
    outcome = c(1, 0, 1, 0, 1, 1),
    income = c(2, 4, 6, 8, 10, 12)
  )
  fit <- ci_tree(
    cbind(rank, outcome) ~ income,
    data = toy_data,
    rank_name = "rank",
    outcome_name = "outcome",
    control = ci_tree_control(minsplit = 1, minbucket = 1, maxdepth = 1)
  )

  score <- ci_tree_validation_gain(fit, toy_data, "rank", "outcome")

  expect_type(score, "double")
  expect_length(score, 1L)
  expect_true(is.finite(score))
})

test_that("ci prediction metrics score simple binary predictions", {
  truth <- c(0, 1, 1, 0)
  estimate <- c(0.1, 0.8, 0.7, 0.2)

  expect_lt(ci_brier_score(truth, estimate), 0.1)
  expect_lt(ci_log_loss(truth, estimate), 0.4)
  expect_equal(ci_roc_auc(truth, estimate), 1)

  out <- ci_prediction_metrics(truth, estimate)
  expect_s3_class(out, "data.table")
  expect_true(all(c("brier", "log_loss", "roc_auc") %in% names(out)))
})
